  // ---- onboarding: profile setup (name / gender / dob) ----
  'profileSetup.title': { en: 'Tell us about you', hi: 'अपने बारे में बताएं', bn: 'আপনার সম্পর্কে বলুন', mr: 'तुमच्याबद्दल सांगा', gu: 'તમારા વિશે જણાવો', kn: 'ನಿಮ್ಮ ಬಗ್ಗೆ ತಿಳಿಸಿ', ta: 'உங்களைப் பற்றி சொல்லுங்கள்' },
  'profileSetup.subtitle': { en: 'Your name is how neighbours will see you. This helps keep Daata friendly and safe.', hi: 'आपका नाम वही है जो पड़ोसी देखेंगे। इससे Daata दोस्ताना और सुरक्षित रहता है।', bn: 'আপনার নাম প্রতিবেশীরা দেখতে পাবে। এটি Daata-কে বন্ধুত্বপূর্ণ ও নিরাপদ রাখতে সাহায্য করে।', mr: 'तुमचे नाव शेजाऱ्यांना दिसेल. यामुळे Daata मैत्रीपूर्ण आणि सुरक्षित राहते.', gu: 'તમારું નામ પડોશીઓ જોશે. આ Daata ને મૈત્રીપૂર્ણ અને સલામત રાખવામાં મદદ કરે છે.', kn: 'ನಿಮ್ಮ ಹೆಸರನ್ನು ನೆರೆಯವರು ನೋಡುತ್ತಾರೆ. ಇದು Daata ಅನ್ನು ಸ್ನೇಹಪರ ಮತ್ತು ಸುರಕ್ಷಿತವಾಗಿಡಲು ಸಹಾಯ ಮಾಡುತ್ತದೆ.', ta: 'உங்கள் பெயரை அண்டை வீட்டார் பார்ப்பார்கள். இது Daata-வை நட்பாகவும் பாதுகாப்பாகவும் வைக்க உதவுகிறது.' },
  'profileSetup.hint': { en: 'You can change these later in Settings.', hi: 'आप इन्हें बाद में सेटिंग्स में बदल सकते हैं।', bn: 'আপনি পরে সেটিংসে এগুলি পরিবর্তন করতে পারেন।', mr: 'तुम्ही हे नंतर सेटिंग्जमध्ये बदलू शकता.', gu: 'તમે આ પછીથી સેટિંગ્સમાં બદલી શકો છો.', kn: 'ನೀವು ಇವುಗಳನ್ನು ನಂತರ ಸೆಟ್ಟಿಂಗ್‌ಗಳಲ್ಲಿ ಬದಲಾಯಿಸಬಹುದು.', ta: 'இவற்றை பின்னர் அமைப்புகளில் மாற்றலாம்.' },
  'profile.nameLabel': { en: 'Your name', hi: 'आपका नाम', bn: 'আপনার নাম', mr: 'तुमचे नाव', gu: 'તમારું નામ', kn: 'ನಿಮ್ಮ ಹೆಸರು', ta: 'உங்கள் பெயர்' },
