  'detail.awayApprox': { en: '{dist} away · approximate area', hi: '{dist} दूर · अनुमानित क्षेत्र', bn: '{dist} দূরে · আনুমানিক এলাকা', mr: '{dist} दूर · अंदाजे परिसर', gu: '{dist} દૂર · અંદાજિત વિસ્તાર', kn: '{dist} ದೂರ · ಅಂದಾಜು ಪ್ರದೇಶ', ta: '{dist} தொலைவில் · தோராயமான பகுதி' },
  'detail.exactAfterAccept': { en: 'The exact address is shared only after the giver accepts your request.', hi: 'सटीक पता तभी साझा किया जाता है जब देने वाला आपका अनुरोध स्वीकार कर ले।', bn: 'দাতা আপনার অনুরোধ গ্রহণ করার পরেই সঠিক ঠিকানা শেয়ার করা হয়।', mr: 'देणारा तुमची विनंती स्वीकारल्यानंतरच नेमका पत्ता शेअर केला जातो.', gu: 'આપનાર તમારી વિનંતી સ્વીકારે પછી જ ચોક્કસ સરનામું શેર થાય છે.', kn: 'ನೀಡುವವರು ನಿಮ್ಮ ವಿನಂತಿಯನ್ನು ಸ್ವೀಕರಿಸಿದ ನಂತರವೇ ನಿಖರ ವಿಳಾಸ ಹಂಚಲಾಗುತ್ತದೆ.', ta: 'கொடுப்பவர் உங்கள் கோரிக்கையை ஏற்ற பிறகே சரியான முகவரி பகிரப்படும்.' },
  'detail.useMyLocation': { en: 'Use my location to see distance', hi: 'दूरी देखने के लिए मेरा स्थान उपयोग करें', bn: 'দূরত্ব দেখতে আমার অবস্থান ব্যবহার করুন', mr: 'अंतर पाहण्यासाठी माझे स्थान वापरा', gu: 'અંતર જોવા મારું સ્થાન વાપરો', kn: 'ದೂರ ನೋಡಲು ನನ್ನ ಸ್ಥಳ ಬಳಸಿ', ta: 'தூரத்தைப் பார்க்க எனது இருப்பிடத்தைப் பயன்படுத்து' },
  'detail.markTaken': { en: 'Mark as Taken', hi: 'लिया गया चिह्नित करें', bn: 'নেওয়া হয়েছে চিহ্নিত করুন', mr: 'घेतले म्हणून चिन्हांकित करा', gu: 'લેવાયેલ તરીકે ચિહ્નિત કરો', kn: 'ತೆಗೆದುಕೊಳ್ಳಲಾಗಿದೆ ಎಂದು ಗುರುತಿಸಿ', ta: 'எடுக்கப்பட்டதாகக் குறி' },
  'detail.wantThis': { en: 'I want this', hi: 'मुझे यह चाहिए', bn: 'আমি এটি চাই', mr: 'मला हे हवे आहे', gu: 'મને આ જોઈએ છે', kn: 'ನನಗೆ ಇದು ಬೇಕು', ta: 'எனக்கு இது வேண்டும்' },
  'detail.requested': { en: 'Requested', hi: 'अनुरोध किया गया', bn: 'অনুরোধ করা হয়েছে', mr: 'विनंती केली', gu: 'વિનંતી કરી', kn: 'ವಿನಂತಿಸಲಾಗಿದೆ', ta: 'கோரப்பட்டது' },
  'detail.message': { en: 'Message {name}', hi: '{name} को संदेश भेजें', bn: '{name}-কে বার্তা পাঠান', mr: '{name} ला संदेश पाठवा', gu: '{name} ને સંદેશ મોકલો', kn: '{name} ಗೆ ಸಂದೇಶ ಕಳುಹಿಸಿ', ta: '{name} க்கு செய்தி அனுப்பு' },
  'detail.requestDeclined': { en: 'Request declined', hi: 'अनुरोध अस्वीकृत', bn: 'অনুরোধ প্রত্যাখ্যাত', mr: 'विनंती नाकारली', gu: 'વિનંતી નકારી', kn: 'ವಿನಂತಿ ತಿರಸ್ಕರಿಸಲಾಗಿದೆ', ta: 'கோரிக்கை நிராகரிக்கப்பட்டது' },

