  'post.cameraNeededMsg': { en: 'Enable camera permission to take a photo.', hi: 'फ़ोटो लेने के लिए कैमरा अनुमति सक्षम करें।', bn: 'ছবি তুলতে ক্যামেরা অনুমতি সক্ষম করুন।', mr: 'फोटो काढण्यासाठी कॅमेरा परवानगी सक्षम करा.', gu: 'ફોટો લેવા માટે કેમેરા પરવાનગી સક્ષમ કરો.', kn: 'ಫೋಟೋ ತೆಗೆಯಲು ಕ್ಯಾಮೆರಾ ಅನುಮತಿಯನ್ನು ಸಕ್ರಿಯಗೊಳಿಸಿ.', ta: 'புகைப்படம் எடுக்க கேமரா அனுமதியை இயக்கவும்.' },
  'post.titleLabel': { en: 'Title', hi: 'शीर्षक', bn: 'শিরোনাম', mr: 'शीर्षक', gu: 'શીર્ષક', kn: 'ಶೀರ್ಷಿಕೆ', ta: 'தலைப்பு' },
