  'manage.deleteConfirm': { en: 'Delete “{title}”? This can’t be undone.', hi: '“{title}” हटाएं? यह पूर्ववत नहीं किया जा सकता।', bn: '“{title}” মুছবেন? এটি আর ফেরানো যাবে না।', mr: '“{title}” हटवायचे? हे पूर्ववत करता येणार नाही.', gu: '“{title}” કાઢી નાખવું? આ પાછું લાવી શકાશે નહીં.', kn: '“{title}” ಅಳಿಸಬೇಕೆ? ಇದನ್ನು ರದ್ದುಗೊಳಿಸಲಾಗದು.', ta: '“{title}” நீக்கவா? இதைச் செயல்தவிர்க்க முடியாது.' },
  'manage.whoPicked': { en: 'Who picked it up?', hi: 'इसे किसने लिया?', bn: 'এটি কে নিয়েছে?', mr: 'ते कोणी घेतले?', gu: 'આ કોણે લીધું?', kn: 'ಇದನ್ನು ಯಾರು ತೆಗೆದುಕೊಂಡರು?', ta: 'இதை யார் எடுத்தார்?' },
  'manage.noRequestsYet': { en: 'No one has requested this item yet. If you no longer want to give it, delete the listing.', hi: 'अभी तक किसी ने इस वस्तु का अनुरोध नहीं किया है। यदि आप इसे अब नहीं देना चाहते, तो लिस्टिंग हटा दें।', bn: 'এখনও কেউ এই আইটেমটি অনুরোধ করেননি। আপনি যদি এটি আর দিতে না চান, তালিকাটি মুছে ফেলুন।', mr: 'अद्याप कोणीही या वस्तूची विनंती केलेली नाही. तुम्हाला ती द्यायची नसेल, तर यादी हटवा.', gu: 'હજી સુધી કોઈએ આ વસ્તુની વિનંતી કરી નથી. જો તમે હવે તે આપવા ન માંગતા હો, તો લિસ્ટિંગ કાઢી નાખો.', kn: 'ಈ ವಸ್ತುವನ್ನು ಇನ್ನೂ ಯಾರೂ ವಿನಂತಿಸಿಲ್ಲ. ನೀವು ಇದನ್ನು ಇನ್ನು ಕೊಡಲು ಬಯಸದಿದ್ದರೆ, ಪಟ್ಟಿಯನ್ನು ಅಳಿಸಿ.', ta: 'இந்தப் பொருளை இன்னும் யாரும் கோரவில்லை. நீங்கள் இனி இதைக் கொடுக்க விரும்பவில்லை எனில், பட்டியலை நீக்கவும்.' },
  'manage.choose': { en: 'Choose', hi: 'चुनें', bn: 'বেছে নিন', mr: 'निवडा', gu: 'પસંદ કરો', kn: 'ಆರಿಸಿ', ta: 'தேர்வு செய்' },

