/**
 * Translate a key for the given language, falling back to English. Supports
 * named placeholders, e.g. translate('en', 'feed.nothingIn', { loc: 'Pune' })
 * for an entry like "Nothing in {loc}".
 */
export function translate(lang: LangCode, key: string, params?: Record<string, string | number>): string {
  const entry = TR[key];
  let str = entry ? entry[lang] ?? entry.en : key;
  if (params) {
    for (const k of Object.keys(params)) {
      str = str.split(`{${k}}`).join(String(params[k]));
    }
  }
  return str;
}
